function loadSlowShutter(deviceIp) {
    var sel = document.getElementById('slowShutterSelect');
    if (!sel) return;
    
    // v8.45: 从function.json读取DSS支持倍率
    if (!deviceFunctionData || !deviceFunctionData.functions || !deviceFunctionData.functions.slow_shutter) {
        sel.disabled = true;
        sel.innerHTML = '<option value="">设备不支持</option>';
        return;
    }
    
    var dss = deviceFunctionData.functions.slow_shutter;
    if (!dss.supported) {
        sel.disabled = true;
        sel.innerHTML = '<option value="">设备不支持</option>';
        return;
    }
    
    sel.disabled = false;
    sel.innerHTML = '';
    
    // 添加"关闭"选项
    var offOpt = document.createElement('option');
    offOpt.value = 'off';
    offOpt.textContent = '关闭';
    sel.appendChild(offOpt);
    
    // 从opt_values添加倍率选项
    if (dss.opt_values && Array.isArray(dss.opt_values)) {
        dss.opt_values.forEach(function(level) {
            var opt = document.createElement('option');
            opt.value = level;
            opt.textContent = level;
            sel.appendChild(opt);
        });
    }
    
    // 获取当前DSS状态并设置选中项
    apiGet('/api/v1/ptz/' + deviceIp + '/image/slow-shutter').then(function(r) {
        if (r && r.success && r.data) {
            sel.value = r.data.enabled && r.data.dss_level ? r.data.dss_level : 'off';
            if (typeof mediaLog === 'function') mediaLog('慢快门加载成功', 'info');
        } else {
            if (typeof mediaLog === 'function') mediaLog('慢快门加载失败', 'error');
        }
    }).catch(function(e) {
        if (typeof mediaLog === 'function') mediaLog('慢快门加载异常: ' + e.message, 'error');
    });
}

function setSlowShutter(val) {
    var dev = window.connectedDevice ? window.connectedDevice.ip : null;
    if (!dev) return;
    apiPut('/api/v1/ptz/' + dev + '/image/slow-shutter', { dss_level: val }).then(function(r) {
        if (r && r.success) {
            showToast('success', r.message);
            if (typeof operationLog === 'function') operationLog('慢快门: ' + r.message, 'success');
            if (typeof mediaLog === 'function') mediaLog('慢快门设置: ' + r.message, 'success');
            var sel = document.getElementById('slowShutterSelect');
            if (sel) sel.value = val;
        } else {
            showToast('error', '慢快门设置失败: ' + (r ? r.message : '未知错误'));
            if (typeof operationLog === 'function') operationLog('慢快门设置失败: ' + (r ? r.message : ''), 'error');
            if (typeof mediaLog === 'function') mediaLog('慢快门设置失败: ' + (r ? r.message : ''), 'error');
        }
    }).catch(function(e) {
        showToast('error', '慢快门请求异常: ' + e.message);
        if (typeof operationLog === 'function') operationLog('慢快门请求异常: ' + e.message, 'error');
        if (typeof mediaLog === 'function') mediaLog('慢快门请求异常: ' + e.message, 'error');
        loadSlowShutter(dev);
    });
}
