function updateSwitchHighlight(switchId, selectedValue) {
    var switchEl = document.getElementById(switchId);
    if (!switchEl) return;
    var buttons = switchEl.querySelectorAll('.ts-btn');
    buttons.forEach(function(btn) {
        if (btn.dataset.value === selectedValue) {
            btn.classList.add('active');
        } else {
            btn.classList.remove('active');
        }
    });
}

