    except Exception as e:
        return {"success": False, "message": f"设置DSS异常: {e}"}

@api_router.get("/ptz/{device_id}/image/settings-saved", summary="获取设备保存的设置", tags=["Image"])
async def get_saved_settings(device_id: str) -> dict:
    """获取设备保存的图像参数设置 (用于记忆恢复)。"""
    try:
        from src.advanced.device_settings import load_settings
        mac_clean = device_id.replace(":", "").replace("-", "").lower()
        if len(mac_clean) != 12:
            return {"success": False, "message": "无效的设备标识"}
        
        settings = load_settings(mac_clean)
        return {"success": True, "data": settings or {}}
    except Exception as e:
        return {"success": False, "message": f"获取保存设置失败: {e}"}
