async def set_slow_shutter(device_id: str, body: dict) -> dict:
    mgr = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZDeviceController未初始化"}
    target_ip = _resolve_device_id_to_ip(mgr, device_id)
    if not target_ip:
        return {"success": False, "message": f"无法解析设备标识: {device_id}"}
    ctrl, err = mgr._get_controller(target_ip)
    if err:
        return {"success": False, "message": err}
    client = ctrl.client
    dss_level = body.get("dss_level", "")
    try:
        # GET DSS 轻量 XML，修改后 PUT 回去（避免 GET 整个 /Image/channels/1）
        import re
        get_resp = await asyncio.to_thread(client.get, "/Image/channels/1/DSS")
        if get_resp.status_code != 200:
            return {"success": False, "message": f"获取DSS失败: HTTP {get_resp.status_code}"}
        xml_str = get_resp.xml
        
        if dss_level == "off":
            enabled = "false"
            level_str = "*1"
        else:
            enabled = "true"
            level_str = dss_level
        
        xml_str = re.sub(r'(<enabled>)[^<]*(</enabled>)', f'\\g<1>{enabled}\\g<2>', xml_str, flags=re.IGNORECASE)
        xml_str = re.sub(r'(<DSSLevel>)[^<]*(</DSSLevel>)', f'\\g<1>{level_str}\\g<2>', xml_str, flags=re.IGNORECASE)
        put_resp = await asyncio.to_thread(client.put, "/Image/channels/1/DSS", xml_str)
        if put_resp.status_code == 200:
            log_info("image", "dss", {"device": device_id, "level": dss_level})
            try:
                mac_clean = device_id.replace(":", "").replace("-", "").lower()
                if len(mac_clean) == 12:
                    save_device_settings(mac_clean, {"slow_shutter": {"dss_level": dss_level, "enabled": dss_level != "off"}})
            except Exception:
                pass
            return {"success": True, "message": "慢快门: " + ("关闭" if dss_level == "off" else dss_level)}
        return {"success": False, "message": f"设置失败: HTTP {put_resp.status_code}"}

