    # DSS 是 /Image/channels/1 的子元素，从完整配置中提取
    resp = await asyncio.to_thread(client.get, "/Image/channels/1")
    if resp.status_code != 200:
        return {"success": False, "message": f"获取设备配置失败: HTTP {resp.status_code}"}
    import xml.etree.ElementTree as ET
    root = ET.fromstring(resp.xml)
    enabled = False
    dss_level = ""
    for elem in root.iter():
        tag = elem.tag.split("}")[-1] if "}" in elem.tag else elem.tag
        if tag == "DSS":
            for child in elem:
                child_tag = child.tag.split("}")[-1] if "}" in child.tag else child.tag
                if child_tag == "enabled":
                    enabled = (child.text or "").strip().lower() == "true"
                elif child_tag == "DSSLevel":
                    dss_level = (child.text or "").strip()
    return {"success": True, "data": {"supported": True, "enabled": enabled, "dss_level": dss_level}}
except Exception as e:
    return {"success": False, "message": f"获取DSS异常: {e}"}

