            if (r && r.success && r.data) {
                var panEl = document.getElementById('ptzPan');
                var tiltEl = document.getElementById('ptzTilt');
                var zoomEl = document.getElementById('ptzZoom');
                if (panEl) panEl.textContent = r.data.pan || 0;
                if (tiltEl) tiltEl.textContent = r.data.tilt || 0;
                if (zoomEl) zoomEl.textContent = r.data.zoom || 0;
            }
        }).catch(function(e) {});

        // 2. 白平衡 R/B - v7.55: 只显示数值
        apiGet('/api/v1/ptz/' + dev + '/image/whitebalance').then(function(r) {
            if (r && r.success && r.data) {
                var wb = r.data;
                var rEl = document.getElementById('ptzWbR');
                var bEl = document.getElementById('ptzWbB');
                if (rEl) rEl.textContent = wb.red_gain || '--';
                if (bEl) bEl.textContent = wb.blue_gain || '--';
            }
        }).catch(function(e) {});

        // 3. 降噪空域/时域 - v7.55: 只显示数值
