@api_router.get("/ptz/{device_id}/image/filter", summary="获取滤镜与日夜模式", tags=["Image"])
async def get_filter_settings(device_id: str) -> dict:
    """获取当前 dayNightMode 和 IrcutFilterType 设置。"""
    import xml.etree.ElementTree as ET
    mgr: PTZDeviceController | None = _managers.get("ptz_controller")
    if not mgr:
        return {"success": False, "message": "PTZDeviceController未初始化"}

    target_ip = _resolve_device_id_to_ip(mgr, device_id)
    if not target_ip:
        return {"success": False, "message": f"无法解析设备标识: {device_id}"}

    ctrl, err = mgr._get_controller(target_ip)
    if err:
        return {"success": False, "message": err}

    client = ctrl.client
    import xml.etree.ElementTree as ET
    import re
    try:
        # dayNightMode: 从 /Image/channels/1 正则提取（处理可能的命名空间前缀）
        day_night = "auto"
        resp = await asyncio.to_thread(client.get, "/Image/channels/1")
        if resp.status_code == 200:
            m = re.search(r'<[^>]*dayNightMode[^>]*>([^<]*)</[^>]*dayNightMode[^>]*>', resp.xml, re.IGNORECASE)
            if m:
                day_night = m.group(1).strip()

        # IrcutFilter: 从 /Image/channels/1/IrcutFilter 获取
        ir_cut = "unknown"
        ircut_resp = await asyncio.to_thread(client.get, "/Image/channels/1/IrcutFilter")
        if ircut_resp.status_code == 200:
            ircut_root = ET.fromstring(ircut_resp.xml)
            for elem in ircut_root.iter():
                tag = elem.tag.split("}")[-1] if "}" in elem.tag else elem.tag
                if tag == "IrcutFilterAction":
                    action = (elem.text or "").strip()
                    # 映射: day→on, night→off
                    reverse_map = {"day": "on", "night": "off"}
                    ir_cut = reverse_map.get(action, action)

        return {
            "success": True,
            "data": {
                "dayNightMode": day_night,
                "IrcutFilterType": ir_cut
            }
        }
    except Exception as e:
        return {"success": False, "message": f"获取滤镜设置异常: {e}"}


